+		return;
+	}
+	cpu_monitor(state, 0, 0);
+	if (*state == STATE_MWAIT)
+		__asm __volatile("sti; mwait" : : "a" (MWAIT_C1), "c" (0));
 	else
-		__asm __volatile("sti; hlt");
+		enable_intr();
+	*state = STATE_RUNNING;
 }

